def fibp(n: int) -> tuple[int, int]:
    if n == 0: return (0, 1)
    a, b = fibp(n >> 1)
    c = a * (2 * b - a)
    d = a * a + b * b
    return (d, c + d) if (n & 1) else (c, d)
def a(n: int) -> int:
    if n < 2: return n + 1
    f = fibp(n)[0]
    ff = fibp(n * n - 1)[0]
    return ff // (f * f + (-1 if n & 1 else 1))
A = [a(n) for n in range(17)]; print(A)  # _Peter Luschny_, May 24 2026

